class Solution:
    def numberOfWays(self, n: int, x: int) -> int:
        MOD = 10**9 + 7
        visited = set()
        count = 0

        def backtrack(remaining, start):
            nonlocal count
            if remaining == 0:
                count = (count + 1) % MOD
                return
            for i in range(start, n + 1):
                power = i ** x
                if power > remaining:
                    break
                if i not in visited:
                    visited.add(i)
                    backtrack(remaining - power, i + 1)
                    visited.remove(i)

        backtrack(n, 1)
        return count
